import React, { useState } from 'react'

function CountButtExam(){
    const [count, setCount] = useState(0)


    return (
        <div>
            <h1>
                {count}

            </h1>

                <button onClick={() => setCount(count + 1)}>

                Plus
            </button>


        </div>
    )
} 
export default CountButtExam
